// src/stats.ts
import { existsSync as existsSync7, readdirSync as readdirSync3, statSync as statSync3 } from "node:fs";
import { join as join4 } from "node:path";
function buildStats() {
  const status = ensureConsistent();
  const dir = skillsDir();
  const totalBytes = existsSync7(dir) ? dirSize(dir) : 0;
  const totalSkills = Object.keys(status.skills).length;
  const top = Object.entries(status.skills).sort((a, b) => (b[1].use_count ?? 0) - (a[1].use_count ?? 0)).slice(0, 5);
  const sevenDaysAgo = Date.now() - 7 * 864e5;
  const last7d = Object.values(status.skills).filter((e) => Date.parse(e.last_used_at) >= sevenDaysAgo).length;
  const log = readRecentQueryLog(50);
  const avg = log.length ? log.reduce((s, r) => s + r.candidate_count, 0) / log.length : 0;
  const lines = [];
  lines.push("## dora skills");
  lines.push("");
  lines.push(`- Total cached: ${totalSkills} skills, ${(totalBytes / 1048576).toFixed(1)} MB on disk`);
  lines.push("- Top by use_count:");
  if (top.length === 0) {
    lines.push("  _(none)_");
  } else {
    lines.push("  | key | uses | last used | sec |");
    lines.push("  |---|---|---|---|");
    for (const [k, e] of top) {
      const days = Math.max(0, Math.floor((Date.now() - Date.parse(e.last_used_at)) / 864e5));
      lines.push(`  | ${k} | ${e.use_count ?? 0} | ${days}d ago | ${e.security_level} |`);
    }
  }
  lines.push(`- Used in last 7d: ${last7d}`);
  lines.push(`- Avg candidates per query: ${avg.toFixed(1)} (last ${log.length} queries)`);
  return lines.join("\n");
}
function dirSize(dir) {
  let total = 0;
  const queue = [dir];
  while (queue.length) {
    const cur = queue.shift();
    let entries = [];
    try {
      entries = readdirSync3(cur);
    } catch {
      continue;
    }
    for (const e of entries) {
      const full = join4(cur, e);
      let st;
      try {
        st = statSync3(full);
      } catch {
        continue;
      }
      if (st.isDirectory()) queue.push(full);
      else total += st.size;
    }
  }
  return total;
}

// src/upgrade.ts
function buildUpgradeCommand() {
  const root = process.env.CLAUDE_PLUGIN_ROOT;
  if (root && root.length > 0) {
    const segs = root.replace(/\/+$/, "").split("/");
    const plugin = segs.at(-2);
    const marketplace = segs.at(-3);
    if (plugin && marketplace) {
      return `claude plugin update ${plugin}@${marketplace}`;
    }
    return `claude plugin update dora@dora`;
  }
  return "npm install -g dora@latest && dora doctor";
}

// src/diagnostics/checks/node.ts
async function checkNode() {
  const major = parseInt(process.versions.node.split(".")[0], 10);
  return { name: "Node 18+", status: major >= 18 ? "pass" : "fail", detail: `v${process.versions.node}` };
}

