// src/diagnostics/checks/engine.ts
async function checkEngine() {
  const cfg = loadConfig();
  const t0 = Date.now();
  const ctrl = new AbortController();
  const timer = setTimeout(() => ctrl.abort(), cfg.query_timeout_seconds * 1e3);
  try {
    const resp = await fetch(cfg.skill_query_url.replace(/\/$/, "") + "/retrieve", {
      method: "POST",
      signal: ctrl.signal,
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ query: "doctor-probe" })
    });
    const ms = Date.now() - t0;
    if (resp.ok || resp.status === 404) {
      return { name: "engine reachable", status: "pass", detail: `${cfg.skill_query_url}, ${ms}ms` };
    }
    return { name: "engine reachable", status: "fail", detail: `HTTP ${resp.status}` };
  } catch (e) {
    return { name: "engine reachable", status: "fail", detail: e.message };
  } finally {
    clearTimeout(timer);
  }
}

// src/diagnostics/checks/local-index.ts
async function checkLocalIndex() {
  try {
    await localQuery("smoke", 1);
    return { name: "local index", status: "pass" };
  } catch (e) {
    if (isDoraError(e)) {
      if (e.code === "empty_candidates") {
        return { name: "local index", status: "pass" };
      }
      const reason = e.detail?.reason;
      return { name: "local index", status: "fail", detail: reason ?? e.code };
    }
    return { name: "local index", status: "fail", detail: e.message };
  }
}

// src/diagnostics/checks/status.ts
async function checkStatus() {
  try {
    const s = ensureConsistent();
    const rows = listSkills();
    const total = Object.keys(s.skills).length;
    const orphans = rows.filter((r) => r.status === "orphan").length;
    const broken = rows.filter((r) => r.status === "broken").length;
    return {
      name: "status.yaml consistent",
      status: broken > 0 ? "warn" : "pass",
      detail: `${total} skills, ${orphans} orphan, ${broken} broken`
    };
  } catch (e) {
    return { name: "status.yaml consistent", status: "fail", detail: e.message };
  }
}

